document.getElementById('quote-form').addEventListener('submit', async function (e) {
    e.preventDefault();

    // 1. Elements ko pehle hi pakar lein
    const formElement = this;
    const successUI = document.getElementById('success-message');
    const submitBtn = document.getElementById('submitBtn');
    const originalText = submitBtn.textContent;

    // 2. Loading State
    submitBtn.textContent = "Sending...";
    submitBtn.disabled = true;

    // 3. Data Mapping
    const templateParams = {
        client_name: document.getElementById("customerName").value,
        client_email: document.getElementById("email").value,
        phone: document.getElementById("phone").value,
        passengers: document.getElementById("passengers").value,
        vehicle_type: document.getElementById("vehicleType").value,
        service_type: document.getElementById("serviceType").value,
        pickup: document.getElementById("pickupAddress").value,
        dropoff: document.getElementById("dropoffAddress").value,
        date_time: document.getElementById("date").value + " at " + document.getElementById("time").value
    };

    try {
        const response = await fetch('https://api.emailjs.com/api/v1.0/email/send', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                service_id: 'service_05obng6',
                template_id: 'template_mupr0xf',
                user_id: '_4emOGNfMrl5llxnP',
                template_params: templateParams
            })
        });

        // Vercel check: Response status check karein
        if (response.ok || response.status === 200) {
            console.log("Success! Switching UI...");

            // Redirect to the dedicated success page
            window.location.href = './thanks.html';
            formElement.reset();
        } else {
            throw new Error("EmailJS Server Error");
        }
    } catch (error) {
        console.error("Submission Error:", error);
        alert("Booking error. Please call 0301-1954994 directly.");
    } finally {
        submitBtn.textContent = originalText;
        submitBtn.disabled = false;
    }
});

// Improve UX: Make the entire date/time inputs click to open the native picker
const dateInput = document.getElementById("date");
const timeInput = document.getElementById("time");

if (dateInput && timeInput) {
    [dateInput, timeInput].forEach(input => {
        input.addEventListener('click', () => {
            try {
                if (typeof input.showPicker === 'function') {
                    input.showPicker();
                }
            } catch (err) {
                console.log("Picker not supported or already open.");
            }
        });
    });
}